def search_contacts(
        whatsapp: Annotated[WhatsApp, Depends("whatsapp")],
        query: str,
) -> str:
    """
    Searches for contacts whose name or phone number contains the query string.
    Only returns individual (non-group) contacts.

    :param query: Case-insensitive substring to match against contact names or phone numbers.
    :return: Text table with columns: `unique_id | name | phone`; or "No contacts found matching the query."
    """
    results = []
    query_lower = query.lower()

    for contact in whatsapp.contacts.values():
        name_match = contact.name and query_lower in contact.name.lower()
        phone_match = query_lower in contact.phone.lower()
        if name_match or phone_match:
            results.append({
                "unique_id": contact.unique_id,
                "name": contact.name or "(No name)",
                "phone": contact.phone
            })

    if not results:
        return "No contacts found matching the query."

    lines = ["unique_id | name | phone"]
    for r in results:
        lines.append(f"{r['unique_id']} | {r['name']} | {r['phone']}")
    return "\n".join(lines)

def list_chats(
        whatsapp: Annotated[WhatsApp, Depends("whatsapp")],
        query: Optional[str] = None,
) -> str:
    """
    Lists all chats (individual and group), optionally filtered by a name or unique ID substring.

    :param query: Optional case-insensitive substring to filter chats by name or unique ID.
    :return: Text table with columns: `unique_id | name | type`; or "No chats found."
    """
    results = []
    query_lower = query.lower() if query else None

    for chat in whatsapp.chats.values():
        if query_lower:
            name_ok = chat.name and query_lower in chat.name.lower()
            id_ok = query_lower in chat.unique_id.lower()
            if not (name_ok or id_ok):
                continue
        chat_type = "group" if chat.is_group else "individual"
        results.append({
            "unique_id": chat.unique_id,
            "name": chat.name or "(No name)",
            "type": chat_type
        })

    if not results:
        return "No chats found."

    lines = ["unique_id | name | type"]
    for r in results:
        lines.append(f"{r['unique_id']} | {r['name']} | {r['type']}")
    return "\n".join(lines)

def get_latest_message(
        whatsapp: Annotated[WhatsApp, Depends("whatsapp")],
        target_unique_id: str,
        target_type: Optional[str] = None,
) -> str:
    """
    Retrieves the most recent message related to a target (contact or chat).
    - If target is contact: Latest message sent/received with this contact (any chat)
    - If target is chat: Latest message in this chat (any sender)

    :param target_unique_id: Unique ID of contact (xxx@s.whatsapp.net) or chat (xxx@s.whatsapp.net/xxx@g.us)
    :param target_type: Optional filter ('contact'/'chat') to avoid ambiguity (auto-detected if not provided)
    :return: Formatted latest message; or "No interaction found."
    """
    # Auto-detect target type if not provided
    if not target_type:
        if target_unique_id.endswith("@g.us"):
            target_type = "chat"
        else:
            # Check if it's a known contact or chat
            is_contact = target_unique_id in whatsapp.contacts
            is_chat = target_unique_id in whatsapp.chats
            if is_contact and is_chat:
                return "Error: Ambiguous target (exists as both contact and chat). Specify 'target_type' (contact/chat)."
            target_type = "contact" if is_contact else "chat"

    # Find latest message based on target type
    latest_msg = None
    latest_ts = ""
    for msg in whatsapp.messages.values():
        if target_type == "contact":
            # Match messages sent by the contact OR received in the contact's direct chat
            if msg.sender_unique_id == target_unique_id or msg.chat_unique_id == target_unique_id:
                if msg.timestamp > latest_ts:
                    latest_ts = msg.timestamp
                    latest_msg = msg
        elif target_type == "chat":
            # Match messages in the target chat
            if msg.chat_unique_id == target_unique_id:
                if msg.timestamp > latest_ts:
                    latest_ts = msg.timestamp
                    latest_msg = msg

    if not latest_msg:
        return "No interaction found."

    # Resolve sender display name
    sender_display = "Me" if latest_msg.is_from_me else latest_msg.sender_unique_id
    if not latest_msg.is_from_me:
        contact = whatsapp.contacts.get(latest_msg.sender_unique_id)
        if contact and contact.name:
            sender_display = contact.name
        elif latest_msg.sender_unique_id in whatsapp.chats:
            sender_display = whatsapp.chats[latest_msg.sender_unique_id].name or latest_msg.sender_unique_id

    return f"[{latest_msg.timestamp.replace('T', ' ')}] From: {sender_display}: {latest_msg.content}"

def _parse_date_to_days(date_str: str) -> str:
    """Extract YYYY-MM-DD from ISO date (for daily grouping)."""
    return date_str.split("T")[0]


def search_emails(
        account: Annotated[EmailAccount, Depends("email_account")],
        start_date: Optional[str] = None,
        end_date: Optional[str] = None,
        keyword: Optional[str] = None,
        folder: str = "inbox",
) -> str:
    """
    Returns a text table:
    id | from | date | subject
    or:
    No emails found matching the criteria.
    """
    if folder not in ("inbox", "sent"):
        return "Error: Folder must be 'inbox' or 'sent'."

    results = []

    for msg in account.messages:
        if msg.folder != folder:
            continue

        msg_date = _parse_date_to_days(msg.date)

        if start_date and msg_date < start_date:
            continue
        if end_date and msg_date > end_date:
            continue

        if keyword:
            kw = keyword.lower()
            if kw not in msg.subject.lower() and kw not in msg.body.lower():
                continue

        results.append({
            "id": msg.id,  # 无需转换，直接使用字符串 ID
            "from": msg.sender if folder == "inbox" else account.email_address,
            "date": msg.date,
            "subject": msg.subject,
        })

    if not results:
        return "No emails found matching the criteria."

    # 排序优化：优先按 ID 中的数字排序（兼容字符串 ID）
    def extract_sort_key(id_str: str) -> int:
        try:
            return int(id_str.split("_")[-1])
        except (ValueError, IndexError):
            return 0  # 无法解析数字的 ID 排在前面

    results.sort(key=lambda x: extract_sort_key(x["id"]))

    # ---- Build Text Table ----
    lines = ["id | from | date | subject"]
    for r in results:
        lines.append(f"{r['id']} | {r['from']} | {r['date']} | {r['subject']}")
    return "
".join(lines)

def get_email_content(
        account: Annotated[EmailAccount, Depends("email_account")],
        email_id: str,  # 输入已为 str，无需转换
) -> str:
    """Return full email content as a text block."""
    # 核心修改：去掉 int 转换逻辑（直接使用字符串 ID 匹配）
    for msg in account.messages:
        if msg.id == email_id:  # 字符串直接比对
            return (
                f"From: {msg.sender}
"
                f"To: {', '.join(msg.recipients)}
"
                f"CC: {', '.join(msg.cc) if msg.cc else ''}
"
                f"Date: {msg.date}
"
                f"Subject: {msg.subject}
"
                f"Content:
{msg.body}"
            )

    return f"Error: Email with ID {email_id} not found."

def count_daily_emails(
        account: Annotated[EmailAccount, Depends("email_account")],
        start_date: str,
        end_date: str,
) -> str:
    """
    Return output as:
    date | count
    """
    from datetime import datetime, timedelta

    def daterange(start: str, end: str):
        s = datetime.strptime(start, "%Y-%m-%d")
        e = datetime.strptime(end, "%Y-%m-%d")
        cur = s
        while cur <= e:
            yield cur.strftime("%Y-%m-%d")
            cur += timedelta(days=1)

    counts = {day: 0 for day in daterange(start_date, end_date)}

    for msg in account.messages:
        if msg.folder != "inbox":
            continue
        msg_day = _parse_date_to_days(msg.date)
        if msg_day in counts:
            counts[msg_day] += 1

    # ---- Build Text Table ----
    lines = ["date | count"]
    for day in counts:
        lines.append(f"{day} | {counts[day]}")

    return "
".join(lines)
